    59→app.init = function init() {
    60→  var router = null;
    61→
    62→  this.cache = Object.create(null);
    63→  this.engines = Object.create(null);
    64→  this.settings = Object.create(null);
    65→
    66→  this.defaultConfiguration();
    67→
    68→  // Setup getting to lazily add base router
    69→  Object.defineProperty(this, 'router', {
    70→    configurable: true,
    71→    enumerable: true,
    72→    get: function getrouter() {
    73→      if (router === null) {
    74→        router = new Router({
    75→          caseSensitive: this.enabled('case sensitive routing'),
    76→          strict: this.enabled('strict routing')
    77→        });
    78→      }
    79→
    80→      return router;
    81→    }
    82→  });
    83→};
