    94→  this.enable('x-powered-by');
    95→  this.set('etag', 'weak');
    96→  this.set('env', env);
    97→  this.set('query parser', 'simple')
    98→  this.set('subdomain offset', 2);
    99→  this.set('trust proxy', false);
