   107→  debug('booting in %s mode', env);
   108→
   109→  this.on('mount', function onmount(parent) {
   110→    // inherit trust proxy
   111→    if (this.settings[trustProxyDefaultSymbol] === true
   112→      && typeof parent.settings['trust proxy fn'] === 'function') {
   113→      delete this.settings['trust proxy'];
   114→      delete this.settings['trust proxy fn'];
   115→    }
   116→
   117→    // inherit protos
   118→    Object.setPrototypeOf(this.request, parent.request)
   119→    Object.setPrototypeOf(this.response, parent.response)
   120→    Object.setPrototypeOf(this.engines, parent.engines)
   121→    Object.setPrototypeOf(this.settings, parent.settings)
   122→  });
