   154→  var done = callback || finalhandler(req, res, {
   155→    env: this.get('env'),
   156→    onerror: logerror.bind(this)
   157→  });
   158→
   159→  // set powered by header
   160→  if (this.enabled('x-powered-by')) {
   161→    res.setHeader('X-Powered-By', 'Express');
   162→  }
   163→
   164→  // set circular references
   165→  req.res = res;
   166→  res.req = req;
   167→
   168→  // alter the prototypes
   169→  Object.setPrototypeOf(req, this.request)
   170→  Object.setPrototypeOf(res, this.response)
   171→
   172→  // setup locals
   173→  if (!res.locals) {
   174→    res.locals = Object.create(null);
   175→  }
   176→
   177→  this.router.handle(req, res, done);
   178→};
