   192→  var path = '/';
   193→
   194→  // default path to '/'
   195→  // disambiguate app.use([fn])
   196→  if (typeof fn !== 'function') {
   197→    var arg = fn;
   198→
   199→    while (Array.isArray(arg) && arg.length !== 0) {
   200→      arg = arg[0];
   201→    }
   202→
   203→    // first arg is the path
   204→    if (typeof arg !== 'function') {
   205→      offset = 1;
   206→      path = fn;
   207→    }
   208→  }
   209→
   210→  var fns = flatten.call(slice.call(arguments, offset), Infinity);
   211→
   212→  if (fns.length === 0) {
   213→    throw new TypeError('app.use() requires a middleware function')
   214→  }
   215→
   216→  // get router
   217→  var router = this.router;
   218→
   219→  fns.forEach(function (fn) {
   220→    // non-express app
   221→    if (!fn || !fn.handle || !fn.set) {
   222→      return router.use(path, fn);
   223→    }
   224→
   225→    debug('.use app under %s', path);
   226→    fn.mountpath = path;
   227→    fn.parent = this;
   228→
   229→    // restore .app property on req and res
   230→    router.use(path, function mounted_app(req, res, next) {
   231→      var orig = req.app;
   232→      fn.handle(req, res, function (err) {
   233→        Object.setPrototypeOf(req, orig.request)
   234→        Object.setPrototypeOf(res, orig.response)
   235→        next(err);
   236→      });
   237→    });
   238→
   239→    // mounted an app
   240→    fn.emit('mount', this);
   241→  }, this);
   242→
   243→  return this;
   244→};
