   322→app.param = function param(name, fn) {
   323→  if (Array.isArray(name)) {
   324→    for (var i = 0; i < name.length; i++) {
   325→      this.param(name[i], fn);
   326→    }
   327→
   328→    return this;
   329→  }
   330→
   331→  this.router.param(name, fn);
   332→
   333→  return this;
   334→};
