   336→/**
   337→ * Assign `setting` to `val`, or return `setting`'s value.
   338→ *
   339→ *    app.set('foo', 'bar');
   340→ *    app.set('foo');
   341→ *    // => "bar"
   342→ *
   343→ * Mounted servers inherit their parent server's settings.
   344→ *
   345→ * @param {String} setting
   346→ * @param {*} [val]
   347→ * @return {Server} for chaining
   348→ * @public
   349→ */
