   484→/**
   485→ * Special-cased "all" method, applying the given route `path`,
   486→ * middleware, and callback to _every_ HTTP method.
   487→ *
   488→ * @param {String} path
   489→ * @param {Function} ...
   490→ * @return {app} for chaining
   491→ * @public
   492→ */
   493→
   494→app.all = function all(path) {
   495→  var route = this.route(path);
   496→  var args = slice.call(arguments, 1);
   497→
   498→  for (var i = 0; i < methods.length; i++) {
   499→    route[methods[i]].apply(route, args);
   500→  }
   501→
   502→  return this;
   503→};
