   524→  var done = callback;
   525→  var engines = this.engines;
   526→  var opts = options || {};
   527→  var view;
   528→
   529→  // support callback function as second arg
   530→  if (typeof options === 'function') {
   531→    done = options;
   532→    opts = {};
   533→  }
   534→
   535→  // merge options
   536→  var renderOptions = { ...this.locals, ...opts._locals, ...opts };
   537→
   538→  // set .cache unless explicitly provided
   539→  if (renderOptions.cache == null) {
   540→    renderOptions.cache = this.enabled('view cache');
   541→  }
   542→
   543→  // primed cache
   544→  if (renderOptions.cache) {
   545→    view = cache[name];
   546→  }
   547→
   548→  // view
   549→  if (!view) {
   550→    var View = this.get('view');
   551→
   552→    view = new View(name, {
   553→      defaultEngine: this.get('view engine'),
   554→      root: this.get('views'),
   555→      engines: engines
   556→    });
   557→
   558→    if (!view.path) {
   559→      var dirs = Array.isArray(view.root) && view.root.length > 1
   560→        ? 'directories "' + view.root.slice(0, -1).join('", "') + '" or "' + view.root[view.root.length - 1] + '"'
   561→        : 'directory "' + view.root + '"'
