   563→      err.view = view;
   564→      return done(err);
   565→    }
   566→
   567→    // prime the cache
   568→    if (renderOptions.cache) {
   569→      cache[name] = view;
   570→    }
   571→  }
   572→
   573→  // render
   574→  tryRender(view, renderOptions, done);
   575→};
