   577→/**
   578→ * Listen for connections.
   579→ *
   580→ * A node `http.Server` is returned, with this
   581→ * application (which is a `Function`) as its
   582→ * callback. If you wish to create both an HTTP
   583→ * and HTTPS server you may do so with the "http"
   584→ * and "https" modules as shown here:
   585→ *
   586→ *    var http = require('node:http')
   587→ *      , https = require('node:https')
   588→ *      , express = require('express')
   589→ *      , app = express();
   590→ *
   591→ *    http.createServer(app).listen(80);
   592→ *    https.createServer({ ... }, app).listen(443);
   593→ *
   594→ * @return {http.Server}
   595→ * @public
   596→ */
