   598→app.listen = function listen() {
   599→  var server = http.createServer(this)
   600→  var args = slice.call(arguments)
   601→  if (typeof args[args.length - 1] === 'function') {
   602→    var done = args[args.length - 1] = once(args[args.length - 1])
   603→    server.once('error', done)
   604→  }
   605→  return server.listen.apply(server, args)
   606→}
