   608→/**
   609→ * Log error using console.error.
   610→ *
   611→ * @param {Error} err
   612→ * @private
   613→ */
   614→
   615→function logerror(err) {
   616→  /* istanbul ignore next */
   617→  if (this.get('env') !== 'test') console.error(err.stack || err.toString());
   618→}
   619→
   620→/**
   621→ * Try rendering a view.
   622→ * @private
   623→ */
   624→
   625→function tryRender(view, options, callback) {
   626→  try {
   627→    view.render(options, callback);
   628→  } catch (err) {
   629→    callback(err);
   630→  }
   631→}
